import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { useEffect, lazy, Suspense } from 'react';
import { Layout } from './components/Layout';
import { migrateToIndexedDB, isMigrationNeeded } from './services/migration';
import { UndoToastContainer } from './components/UndoToast';
import { useUndoStore } from './stores/useUndoStore';
import { BackupOnboardingModal } from './components/BackupOnboardingModal';
import { useBackupOnboarding } from './hooks/useBackupOnboarding';

// Lazy load all pages for code splitting (including Dashboard)
const Dashboard = lazy(() => import('./pages/Dashboard').then((m) => ({ default: m.Dashboard })));
const Planning = lazy(() => import('./pages/Planning').then((m) => ({ default: m.Planning })));
const Tasks = lazy(() => import('./pages/Tasks').then((m) => ({ default: m.Tasks })));
const Settings = lazy(() => import('./pages/Settings').then((m) => ({ default: m.Settings })));
const Notes = lazy(() => import('./pages/Notes').then((m) => ({ default: m.Notes })));
const Privacy = lazy(() => import('./pages/Privacy').then((m) => ({ default: m.Privacy })));

// Loading fallback component
const PageLoader = () => (
  <div className="flex items-center justify-center min-h-[60vh]">
    <div className="text-center">
      <div className="inline-block h-12 w-12 animate-spin rounded-full border-4 border-solid border-primary-cyan border-r-transparent align-[-0.125em] motion-reduce:animate-[spin_1.5s_linear_infinite]"></div>
      <p className="mt-4 text-sm text-text-light-secondary dark:text-text-dark-secondary">Loading...</p>
    </div>
  </div>
);

/**
 * Main App Component with React Router
 * Uses Layout component to provide consistent header/footer
 */
function App() {
  // Get undo toasts from store
  const toasts = useUndoStore((state) => state.toasts);
  const dismissToast = useUndoStore((state) => state.dismissToast);

  // Backup onboarding
  const { shouldShowModal, dismissModal } = useBackupOnboarding();

  // Run migration and initialize auto-save on app startup
  useEffect(() => {
    const initialize = async () => {
      // Run migration if needed
      if (isMigrationNeeded()) {
        console.log('🚀 Migration needed, starting...');
        const result = await migrateToIndexedDB();
        if (result.success) {
          console.log('✅ Migration complete');
        } else {
          console.error('❌ Migration failed:', result.errors);
        }
      }

      // Initialize auto-save (dynamic import to reduce main bundle)
      const { autoSaveManager } = await import('./services/autoSave');
      await autoSaveManager.initialize();
    };

    initialize();
  }, []);

  return (
    <BrowserRouter>
      <Layout>
        <Suspense fallback={<PageLoader />}>
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/notes" element={<Notes />} />
            <Route path="/planning" element={<Planning />} />
            <Route path="/tasks" element={<Tasks />} />
            <Route path="/settings" element={<Settings />} />
            <Route path="/privacy" element={<Privacy />} />
          </Routes>
        </Suspense>
      </Layout>

      {/* Undo Toast Container - Global across all pages */}
      <UndoToastContainer toasts={toasts} onDismiss={dismissToast} />

      {/* Backup Onboarding Modal */}
      <BackupOnboardingModal isOpen={shouldShowModal} onClose={dismissModal} />
    </BrowserRouter>
  );
}

export default App;

import React, { lazy, Suspense, useEffect } from 'react';

// Lazy load Calendar widget
const Calendar = lazy(() =>
  import('../widgets/Calendar').then((module) => ({ default: module.Calendar }))
);

// Loading fallback
const WidgetLoader = () => (
  <div className="bento-card p-6 h-[800px] animate-pulse">
    <div className="h-full bg-gradient-to-r from-neutral-200 to-neutral-300 dark:from-neutral-800 dark:to-neutral-700 rounded"></div>
  </div>
);

/**
 * Planning Page - Calendar and scheduling
 * Full-featured calendar for event and task planning
 */
export const Planning: React.FC = () => {
  useEffect(() => {
    document.title = 'Neuman Brain';
  }, []);

  return (
    <div className="planning-page">
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
          Planning & Calendar
        </h1>
        <p className="text-text-light-secondary dark:text-text-dark-secondary">
          Manage your schedule, events, and task timelines
        </p>
      </div>

      {/* Calendar Widget */}
      <Suspense fallback={<WidgetLoader />}>
        <Calendar />
      </Suspense>
    </div>
  );
};

